import{ab as t,G as r,H as o,E as e,U as s,N as a,ad as i,X as d}from"./framework-756f1659.js";const p={},l=e("h2",{id:"必看",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#必看","aria-hidden":"true"},"#"),s(" 必看")],-1),c={href:"https://doocs.gitee.io/advanced-java/#/./docs/high-concurrency/why-cache",target:"_blank",rel:"noopener noreferrer"},u={href:"https://javaguide.cn/database/redis/redis-questions-01.html#%E7%AE%80%E5%8D%95%E4%BB%8B%E7%BB%8D%E4%B8%80%E4%B8%8B-redis-%E5%91%97",target:"_blank",rel:"noopener noreferrer"},h=i(`<h2 id="redis支持的数据结构-以及应用场景" tabindex="-1"><a class="header-anchor" href="#redis支持的数据结构-以及应用场景" aria-hidden="true">#</a> Redis支持的数据结构？以及应用场景？</h2><h3 id="strings-字符串" tabindex="-1"><a class="header-anchor" href="#strings-字符串" aria-hidden="true">#</a> strings: 字符串</h3><ol><li><strong>介绍</strong> ：string 数据结构是简单的 key-value 类型。虽然 Redis 是用 C 语言写的，但是 Redis 并没有使用 C 的字符串表示，而是自己构建了一种 <strong>简单动态字符串</strong>（simple dynamic string，<strong>SDS</strong>）。相比于 C 的原生字符串，Redis 的 SDS 不光可以保存文本数据还可以保存二进制数据，并且获取字符串长度复杂度为 O(1)（C 字符串为 O(N)）,除此之外，Redis 的 SDS API 是安全的，不会造成缓冲区溢出。</li><li><strong>常用命令：</strong> <code>set,get,strlen,exists,decr,incr,setex</code> 等等。</li><li><strong>应用场景：</strong> 一般常用在需要计数的场景，比如用户的访问次数、热点文章的点赞转发数量等等。</li></ol><h3 id="lists-列表" tabindex="-1"><a class="header-anchor" href="#lists-列表" aria-hidden="true">#</a> lists: 列表</h3><ol><li><strong>介绍</strong> ：<strong>list</strong> 即是 <strong>链表</strong>。链表是一种非常常见的数据结构，特点是易于数据元素的插入和删除并且可以灵活调整链表长度，但是链表的随机访问困难。许多高级编程语言都内置了链表的实现比如 Java 中的 <strong>LinkedList</strong>，但是 C 语言并没有实现链表，所以 Redis 实现了自己的链表数据结构。Redis 的 list 的实现为一个 <strong>双向链表</strong>，即可以支持反向查找和遍历，更方便操作，不过带来了部分额外的内存开销。</li><li><strong>常用命令:</strong> <code>rpush,lpop,lpush,rpop,lrange,llen</code> 等。</li><li><strong>应用场景:</strong> 发布与订阅或者说消息队列、慢查询。</li></ol><h3 id="hash-散列" tabindex="-1"><a class="header-anchor" href="#hash-散列" aria-hidden="true">#</a> hash: 散列</h3><ol><li><strong>介绍</strong> ：hash 类似于 JDK1.8 前的 HashMap，内部实现也差不多(数组 + 链表)。不过，Redis 的 hash 做了更多优化。另外，hash 是一个 string 类型的 field 和 value 的映射表，<strong>特别适合用于存储对象</strong>，后续操作的时候，你可以直接仅仅修改这个对象中的某个字段的值。 比如我们可以 hash 数据结构来存储用户信息，商品信息等等。</li><li><strong>常用命令：</strong> <code>hset,hmset,hexists,hget,hgetall,hkeys,hvals</code> 等。</li><li><strong>应用场景:</strong> 系统中对象数据的存储。</li></ol><h3 id="sets-集合" tabindex="-1"><a class="header-anchor" href="#sets-集合" aria-hidden="true">#</a> sets: 集合</h3><ol><li><strong>介绍 ：</strong> set 类似于 Java 中的 <code>HashSet</code> 。Redis 中的 set 类型是一种无序集合，集合中的元素没有先后顺序。当你需要存储一个列表数据，又不希望出现重复数据时，set 是一个很好的选择，并且 set 提供了判断某个成员是否在一个 set 集合内的重要接口，这个也是 list 所不能提供的。可以基于 set 轻易实现交集、并集、差集的操作。比如：你可以将一个用户所有的关注人存在一个集合中，将其所有粉丝存在一个集合。Redis 可以非常方便的实现如共同关注、共同粉丝、共同喜好等功能。这个过程也就是求交集的过程。</li><li><strong>常用命令：</strong> <code>sadd,spop,smembers,sismember,scard,sinterstore,sunion</code> 等。</li><li><strong>应用场景:</strong> 需要存放的数据不能重复以及需要获取多个数据源交集和并集等场景</li></ol><h3 id="sorted-sets-有序集合" tabindex="-1"><a class="header-anchor" href="#sorted-sets-有序集合" aria-hidden="true">#</a> sorted sets: 有序集合</h3><ol><li><strong>介绍：</strong> 和 set 相比，sorted set 增加了一个权重参数 score，使得集合中的元素能够按 score 进行有序排列，还可以通过 score 的范围来获取元素的列表。有点像是 Java 中 HashMap 和 TreeSet 的结合体。</li><li><strong>常用命令：</strong> <code>zadd,zcard,zscore,zrange,zrevrange,zrem</code> 等。</li><li><strong>应用场景：</strong> 需要对数据根据某个权重进行排序的场景。比如在直播系统中，实时排行信息包含直播间在线用户列表，各种礼物排行榜，弹幕消息（可以理解为按消息维度的消息排行榜）等信息。</li></ol><h3 id="bitmap" tabindex="-1"><a class="header-anchor" href="#bitmap" aria-hidden="true">#</a> bitmap</h3><ol><li><strong>介绍：</strong> bitmap 存储的是连续的二进制数字（0 和 1），通过 bitmap, 只需要一个 bit 位来表示某个元素对应的值或者状态，key 就是对应元素本身 。我们知道 8 个 bit 可以组成一个 byte，所以 bitmap 本身会极大的节省储存空间。</li><li><strong>常用命令：</strong> <code>setbit</code> 、<code>getbit</code> 、<code>bitcount</code>、<code>bitop</code></li><li><strong>应用场景：</strong> 适合需要保存状态信息（比如是否签到、是否登录...）并需要进一步对这些信息进行分析的场景。比如用户签到情况、活跃用户情况、用户行为统计（比如是否点赞过某个视频）。</li></ol><h3 id="hyperloglogs" tabindex="-1"><a class="header-anchor" href="#hyperloglogs" aria-hidden="true">#</a> hyperloglogs</h3><h3 id="geospatial-地理空间-索引半径查询" tabindex="-1"><a class="header-anchor" href="#geospatial-地理空间-索引半径查询" aria-hidden="true">#</a> geospatial: 地理空间，索引半径查询</h3><h2 id="redis数据结构怎么实现的" tabindex="-1"><a class="header-anchor" href="#redis数据结构怎么实现的" aria-hidden="true">#</a> Redis数据结构怎么实现的？</h2><p>hashMap的数组+链表+红黑树是叫做拉链法,还有一种开放寻址法</p><h2 id="hyperloglog底层怎么实现的-为什么会有误差呢" tabindex="-1"><a class="header-anchor" href="#hyperloglog底层怎么实现的-为什么会有误差呢" aria-hidden="true">#</a> hyperloglog底层怎么实现的？为什么会有误差呢？</h2><h2 id="redis的线程模型-6-0以前" tabindex="-1"><a class="header-anchor" href="#redis的线程模型-6-0以前" aria-hidden="true">#</a> redis的线程模型（6.0以前）？</h2><p><strong>Redis 6.0 之前主要还是单线程处理。</strong></p><p><strong>Redis 基于 Reactor 模式来设计开发了自己的一套高效的事件处理模型</strong> （Netty 的线程模型也基于 Reactor 模式，Reactor 模式不愧是高性能 IO 的基石），这套事件处理模型对应的是 Redis 中的文件事件处理器（file event handler）。由于文件事件处理器（file event handler）是单线程方式运行的，所以我们一般都说 Redis 是单线程模型。</p><p><strong>既然是单线程，那怎么监听大量的客户端连接呢？</strong></p><p>Redis 通过<strong>IO 多路复用程序</strong> 来监听来自客户端的大量连接（或者说是监听多个 socket），它会将感兴趣的事件及类型（读、写）注册到内核中并监听每个事件是否发生。</p><p>这样的好处非常明显： <strong>I/O 多路复用技术的使用让 Redis 不需要额外创建多余的线程来监听客户端的大量连接，降低了资源的消耗</strong>（和 NIO 中的 <code>Selector</code> 组件很像）。</p><p>另外， Redis 服务器是一个事件驱动程序，服务器需要处理两类事件：1. 文件事件; 2. 时间事件。</p><p>时间事件不需要多花时间了解，我们接触最多的还是 <strong>文件事件</strong>（客户端进行读取写入等操作，涉及一系列网络通信）。</p><p>《Redis 设计与实现》有一段话是如是介绍文件事件的，我觉得写得挺不错。</p><blockquote><p>Redis 基于 Reactor 模式开发了自己的网络事件处理器：这个处理器被称为文件事件处理器（file event handler）。文件事件处理器使用 I/O 多路复用（multiplexing）程序来同时监听多个套接字，并根据套接字目前执行的任务来为套接字关联不同的事件处理器。</p><p>当被监听的套接字准备好执行连接应答（accept）、读取（read）、写入（write）、关 闭（close）等操作时，与操作相对应的文件事件就会产生，这时文件事件处理器就会调用套接字之前关联好的事件处理器来处理这些事件。</p><p><strong>虽然文件事件处理器以单线程方式运行，但通过使用 I/O 多路复用程序来监听多个套接字</strong>，文件事件处理器既实现了高性能的网络通信模型，又可以很好地与 Redis 服务器中其他同样以单线程方式运行的模块进行对接，这保持了 Redis 内部单线程设计的简单性。</p></blockquote><p>可以看出，文件事件处理器（file event handler）主要是包含 4 个部分：</p><ul><li>多个 socket（客户端连接）</li><li>IO 多路复用程序（支持多个客户端连接的关键）</li><li>文件事件分派器（将 socket 关联到相应的事件处理器）</li><li>事件处理器（连接应答处理器、命令请求处理器、命令回复处理器）</li></ul><figure><img src="https://javaguide.cn/assets/redis事件处理器.66ac2f3d.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p><strong>Redis6.0 之前 为什么不使用多线程？</strong></p><p>我觉得主要原因有下面 3 个：</p><ol><li>单线程编程容易并且更容易维护；</li><li>Redis 的性能瓶颈不在 CPU ，主要在内存和网络；</li><li>多线程就会存在死锁、线程上下文切换等问题，甚至会影响性能。</li></ol><h2 id="redis6-0-之后为何引入了多线程" tabindex="-1"><a class="header-anchor" href="#redis6-0-之后为何引入了多线程" aria-hidden="true">#</a> Redis6.0 之后为何引入了多线程？</h2><p><strong>Redis6.0 引入多线程主要是为了提高网络 IO 读写性能</strong>，因为这个算是 Redis 中的一个性能瓶颈（Redis 的瓶颈主要受限于内存和网络）。</p><p>虽然，Redis6.0 引入了多线程，但是 Redis 的多线程只是在网络数据的读写这类耗时操作上使用了，执行命令仍然是单线程顺序执行。因此，你也不需要担心线程安全问题。</p><p>Redis6.0 的多线程默认是禁用的，只使用主线程。如需开启需要修改 redis 配置文件 <code>redis.conf</code> ：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>io-threads-do-reads <span class="token function">yes</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>开启多线程后，还需要设置线程数，否则是不生效的。同样需要修改 redis 配置文件 <code>redis.conf</code> :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>io-threads <span class="token number">4</span> <span class="token comment">#官网建议4核的机器建议设置为2或3个线程，8核的建议设置为6个线程</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>推荐阅读：</p>`,42),g={href:"https://mp.weixin.qq.com/s/FZu3acwK6zrCBZQ_3HoUgw",target:"_blank",rel:"noopener noreferrer"},b={href:"https://draveness.me/whys-the-design-redis-single-thread/",target:"_blank",rel:"noopener noreferrer"},k=i(`<h2 id="redis-key的过期策略" tabindex="-1"><a class="header-anchor" href="#redis-key的过期策略" aria-hidden="true">#</a> Redis Key的过期策略？</h2><blockquote><p>过期策略只对设置了过期时间的key生效。</p></blockquote><p>过期策略通常有以下三种：</p><ul><li><strong>定时过期</strong>：定时删除是在设置 key 的过期时间的同时，会创建一个定时器(timer)。定时器在 key 的过期时间来临时，立即执行对 key 的删除操作。该策略可以立即清除过期的数据，对内存很友好；但是会占用大量的CPU资源去处理过期的数据，从而影响缓存的响应时间和吞吐量。</li><li><strong>惰性过期</strong>：只有当访问一个key时，才会判断该key是否已过期，过期则清除。该策略可以最大化地节省CPU资源，却对内存非常不友好。极端情况可能出现大量的过期key没有再次被访问，从而不会被清除，占用大量内存。</li><li><strong>定期过期</strong>：每隔一定的时间，会扫描一定数量的数据库的expires字典中一定数量的key，并清除其中已过期的key。该策略是前两者的一个折中方案。通过调整定时扫描的时间间隔和每次扫描的限定耗时，可以在不同情况下使得CPU和内存资源达到最优的平衡效果。(expires字典会保存所有设置了过期时间的key的过期时间数据，其中，key是指向键空间中的某个键的指针，value是该键的毫秒精度的UNIX时间戳表示的过期时间。键空间是指该Redis集群中保存的所有键。)</li></ul><p><strong>Redis中同时使用了惰性过期和定期过期两种过期策略。</strong></p><p>但是实际上这还是有问题的，如果定期删除漏掉了很多过期 key，然后你也没及时去查，也就没走惰性删除，此时会怎么样？如果大量过期 key 堆积在内存里，导致 Redis 内存块耗尽了，咋整？</p><p>答案是：<strong>走内存淘汰机制</strong>。</p><h2 id="redis的内存淘汰策略" tabindex="-1"><a class="header-anchor" href="#redis的内存淘汰策略" aria-hidden="true">#</a> Redis的内存淘汰策略？</h2><p>Redis的内存淘汰策略是指在Redis的用于缓存的内存不足时，怎么处理需要新写入且需要申请额外空间的数据。</p><p>Redis 提供 6 种数据淘汰策略：</p><ol><li><strong>volatile-lru（least recently used）</strong>：从已设置过期时间的数据集（server.db[i].expires）中挑选最近最少使用的数据淘汰</li><li><strong>volatile-ttl</strong>：从已设置过期时间的数据集（server.db[i].expires）中挑选将要过期的数据淘汰</li><li><strong>volatile-random</strong>：从已设置过期时间的数据集（server.db[i].expires）中任意选择数据淘汰</li><li><strong>allkeys-lru（least recently used）</strong>：当内存不足以容纳新写入数据时，在键空间中，移除最近最少使用的 key（这个是最常用的）</li><li><strong>allkeys-random</strong>：从数据集（server.db[i].dict）中任意选择数据淘汰</li><li><strong>no-eviction</strong>：禁止驱逐数据，也就是说当内存不足以容纳新写入数据时，新写入操作会报错。这个应该没人使用吧！</li></ol><p>4.0 版本后增加以下两种：</p><ol><li><strong>volatile-lfu（least frequently used）</strong>：从已设置过期时间的数据集（server.db[i].expires）中挑选最不经常使用的数据淘汰</li><li><strong>allkeys-lfu（least frequently used）</strong>：当内存不足以容纳新写入数据时，在键空间中，移除最不经常使用的 key</li></ol><h2 id="redis的持久化机制是什么-各自的优缺点-混合持久化" tabindex="-1"><a class="header-anchor" href="#redis的持久化机制是什么-各自的优缺点-混合持久化" aria-hidden="true">#</a> Redis的持久化机制是什么？各自的优缺点（混合持久化）？</h2><p>很多时候我们需要持久化数据也就是将内存中的数据写入到硬盘里面，大部分原因是为了之后重用数据（比如重启机器、机器故障之后恢复数据），或者是为了防止系统故障而将数据备份到一个远程位置。</p><p>Redis 不同于 Memcached 的很重要一点就是，Redis 支持持久化，而且支持两种不同的持久化操作。<strong>Redis 的一种持久化方式叫快照（snapshotting，RDB），另一种方式是只追加文件（append-only file, AOF）</strong>。</p><h3 id="快照-snapshotting-持久化-rdb" tabindex="-1"><a class="header-anchor" href="#快照-snapshotting-持久化-rdb" aria-hidden="true">#</a> 快照（snapshotting）持久化（RDB）</h3><p>Redis 可以通过创建快照来获得存储在内存里面的数据在某个时间点上的副本。Redis 创建快照之后，可以对快照进行备份，可以将快照复制到其他服务器从而创建具有相同数据的服务器副本（Redis 主从结构，主要用来提高 Redis 性能），还可以将快照留在原地以便重启服务器的时候使用。默认下，持久化到dump.rdb文件，并且在redis重启后，自动读取其中文件，据悉，通常情况下一千万的字符串类型键，1GB的快照文件，同步到内存中的时间是20-30秒</p><p>快照持久化是 Redis 默认采用的持久化方式，在<code>redis.conf</code>配置文件中默认有此下配置：</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">save</span> <span class="token value attr-value">900 1         #在900秒(15分钟)之后，如果至少有1个key发生变化，Redis就会自动触发BGSAVE命令创建快照。</span>
<span class="token key attr-name">save</span> <span class="token value attr-value">300 10       #在300秒(5分钟)之后，如果至少有10个key发生变化，Redis就会自动触发BGSAVE命令创建快照。</span>
<span class="token key attr-name">save</span> <span class="token value attr-value">60 10000   #在60秒(1分钟)之后，如果至少有10000个key发生变化，Redis就会自动触发BGSAVE命令创建快照。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这是配置文件默认的策略，他们之间的关系是或，每隔900秒，在这期间变化了至少一个键值，做快照。或者每三百秒，变化了十个键值做快照。或者每六十秒，变化了至少一万个键值，做快照。</p><div class="hint-container tip"><p class="hint-container-title">优点</p><p>1、只有一个文件 dump.rdb，方便持久化。</p><p>2、容灾性好，一个文件可以保存到安全的磁盘。</p><p>3、性能最大化，fork 子进程来完成写操作，让主进程继续处理命令，所以是 IO 最大化。使用单独子进程来进行持久化，主进程不会进行任何 IO 操作，保证了 redis 的高性能</p><p>4、相对于数据集大时，比 AOF 的启动效率更高。</p></div><div class="hint-container warning"><p class="hint-container-title">缺点</p><p>数据安全性低。RDB 是间隔一段时间进行持久化，如果持久化之间 redis 发生故障，会发生数据丢失。所以这种方式更适合数据要求不严谨的时候)</p></div><h3 id="aof-append-only-file-持久化" tabindex="-1"><a class="header-anchor" href="#aof-append-only-file-持久化" aria-hidden="true">#</a> AOF（append-only file）持久化</h3><p>与快照持久化相比，AOF 持久化的实时性更好，因此已成为主流的持久化方案。默认情况下 Redis 没有开启 AOF（append only file）方式的持久化，可以通过 appendonly 参数开启：</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">appendonly</span> <span class="token value attr-value">yes</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>开启 AOF 持久化后每执行一条会更改 Redis 中的数据的命令，Redis 就会将该命令写入到内存缓存 <code>server.aof_buf</code> 中，然后再根据 <code>appendfsync</code> 配置来决定何时将其同步到硬盘中的 AOF 文件。</p><p>AOF 文件的保存位置和 RDB 文件的位置相同，都是通过 dir 参数设置的，默认的文件名是 <code>appendonly.aof</code>。</p><p>在 Redis 的配置文件中存在三种不同的 AOF 持久化方式，它们分别是：</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">appendfsync</span> <span class="token value attr-value">always    #每次有数据修改发生时都会写入AOF文件,这样会严重降低Redis的速度</span>
<span class="token key attr-name">appendfsync</span> <span class="token value attr-value">everysec  #每秒钟同步一次，显式地将多个写命令同步到硬盘</span>
<span class="token key attr-name">appendfsync</span> <span class="token value attr-value">no        #让操作系统决定何时进行同步，默认30s一次</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>为了兼顾数据和写入性能，用户可以考虑 <code>appendfsync everysec</code> 选项（默认值） ，让 Redis 每秒同步一次 AOF 文件，Redis 性能几乎没受到任何影响。而且这样即使出现系统崩溃，用户最多只会丢失一秒之内产生的数据。当硬盘忙于执行写入操作的时候，Redis 还会优雅的放慢自己的速度以便适应硬盘的最大写入速度。</p><div class="hint-container tip"><p class="hint-container-title">优点</p><p>1、数据安全，aof 持久化可以配置 appendfsync 属性，有 always，每进行一次 命令操作就记录到 aof 文件中一次。</p><p>2、通过 append 模式写文件，即使中途服务器宕机，可以通过 redis-check-aof 工具解决数据一致性问题。</p><p>3、AOF 机制的 rewrite 模式。AOF 文件没被 rewrite 之前（文件过大时会对命令 进行合并重写），可以删除其中的某些命令（比如误操作的 flushall）</p></div><div class="hint-container warning"><p class="hint-container-title">缺点</p><p>1、AOF 文件比 RDB 文件大，且恢复速度慢。</p><p>2、数据集大的时候，比 rdb 启动效率低。</p></div><p><strong>混合持久化</strong></p><p>Redis 4.0 开始支持 rdb 和 aof 的混合持久化（默认关闭，可以通过配置项 <code>aof-use-rdb-preamble</code> 开启）。如果把混合持久化打开，AOF 重写的时候就直接把 RDB 的内容写到 AOF 文件开头。这样做的好处是可以结合 RDB 和 AOF 的优点, 快速加载同时避免丢失过多的数据。当然缺点也是有的， AOF 里面的 RDB 部分是压缩格式不再是 AOF 格式，可读性较差。aof 文件内容会变成如下:</p><div class="language-txt line-numbers-mode" data-ext="txt"><pre class="language-txt"><code>RDB FORMAT
AOP FORMAT
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>这样做的好处是可以结合 rdb 和 aof 的优点, 快速加载同时避免丢失过多的数据。当然缺点也是有的， aof 里面的 rdb 部分就是压缩格式不再是 aof 格式，可读性差。</p><p>开启混合存储模式后 aof 文件加载的流程如下：</p><ol><li>aof 文件开头是 rdb 的格式, 先加载 rdb 内容再加载剩余的 aof</li><li>aof 文件开头不是 rdb 的格式，直接以 aof 格式加载整个文件</li></ol><p>判断 aof 文件的前面部分是否为 rdb 格式，只需要判断前 5 个字符是否是 <code>REDIS</code>。这个是因为 rdb 持久化开头就是 <code>REDIS</code>, 同时 aof 命令开头一定不会是 REDIS（命令开头都是*）。</p>`,40),m={href:"https://redis.io/topics/persistence",target:"_blank",rel:"noopener noreferrer"},v=i(`<p><strong>补充内容：AOF 重写</strong></p><p>AOF 重写可以产生一个新的 AOF 文件，这个新的 AOF 文件和原有的 AOF 文件所保存的数据库状态一样，但体积更小。</p><p>AOF 重写是一个有歧义的名字，该功能是通过读取数据库中的键值对来实现的，程序无须对现有 AOF 文件进行任何读入、分析或者写入操作。</p><p>在执行 BGREWRITEAOF 命令时，Redis 服务器会维护一个 AOF 重写缓冲区，该缓冲区会在子进程创建新 AOF 文件期间，记录服务器执行的所有写命令。当子进程完成创建新 AOF 文件的工作之后，服务器会将重写缓冲区中的所有内容追加到新 AOF 文件的末尾，使得新的 AOF 文件保存的数据库状态与现有的数据库状态一致。最后，服务器用新的 AOF 文件替换旧的 AOF 文件，以此来完成 AOF 文件重写操作。</p><h2 id="redis-bigkey" tabindex="-1"><a class="header-anchor" href="#redis-bigkey" aria-hidden="true">#</a> Redis bigkey</h2><h3 id="什么是-bigkey" tabindex="-1"><a class="header-anchor" href="#什么是-bigkey" aria-hidden="true">#</a> 什么是 bigkey？</h3><p>简单来说，如果一个 key 对应的 value 所占用的内存比较大，那这个 key 就可以看作是 bigkey。具体多大才算大呢？有一个不是特别精确的参考标准：string 类型的 value 超过 10 kb，复合类型的 value 包含的元素超过 5000 个（对于复合类型的 value 来说，不一定包含的元素越多，占用的内存就越多）。</p><h3 id="bigkey-有什么危害" tabindex="-1"><a class="header-anchor" href="#bigkey-有什么危害" aria-hidden="true">#</a> bigkey 有什么危害？</h3><p>除了会消耗更多的内存空间，bigkey 对性能也会有比较大的影响。</p><p>因此，我们应该尽量避免写入 bigkey！</p><h3 id="如何发现-bigkey" tabindex="-1"><a class="header-anchor" href="#如何发现-bigkey" aria-hidden="true">#</a> 如何发现 bigkey？</h3><p><strong>1、使用 Redis 自带的 <code>--bigkeys</code> 参数来查找。</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># redis-cli -p 6379 --bigkeys</span>

<span class="token comment"># Scanning the entire keyspace to find biggest keys as well as</span>
<span class="token comment"># average sizes per key type.  You can use -i 0.1 to sleep 0.1 sec</span>
<span class="token comment"># per 100 SCAN commands (not usually needed).</span>

<span class="token punctuation">[</span>00.00%<span class="token punctuation">]</span> Biggest string found so far <span class="token string">&#39;&quot;ballcat:oauth:refresh_auth:f6cdb384-9a9d-4f2f-af01-dc3f28057c20&quot;&#39;</span> with <span class="token number">4437</span> bytes
<span class="token punctuation">[</span>00.00%<span class="token punctuation">]</span> Biggest list   found so far <span class="token string">&#39;&quot;my-list&quot;&#39;</span> with <span class="token number">17</span> items

-------- summary -------

Sampled <span class="token number">5</span> keys <span class="token keyword">in</span> the keyspace<span class="token operator">!</span>
Total key length <span class="token keyword">in</span> bytes is <span class="token number">264</span> <span class="token punctuation">(</span>avg len <span class="token number">52.80</span><span class="token punctuation">)</span>

Biggest   list found <span class="token string">&#39;&quot;my-list&quot;&#39;</span> has <span class="token number">17</span> items
Biggest string found <span class="token string">&#39;&quot;ballcat:oauth:refresh_auth:f6cdb384-9a9d-4f2f-af01-dc3f28057c20&quot;&#39;</span> has <span class="token number">4437</span> bytes

<span class="token number">1</span> lists with <span class="token number">17</span> items <span class="token punctuation">(</span><span class="token number">20.00</span>% of keys, avg size <span class="token number">17.00</span><span class="token punctuation">)</span>
<span class="token number">0</span> hashs with <span class="token number">0</span> fields <span class="token punctuation">(</span>00.00% of keys, avg size <span class="token number">0.00</span><span class="token punctuation">)</span>
<span class="token number">4</span> strings with <span class="token number">4831</span> bytes <span class="token punctuation">(</span><span class="token number">80.00</span>% of keys, avg size <span class="token number">1207.75</span><span class="token punctuation">)</span>
<span class="token number">0</span> streams with <span class="token number">0</span> entries <span class="token punctuation">(</span>00.00% of keys, avg size <span class="token number">0.00</span><span class="token punctuation">)</span>
<span class="token number">0</span> sets with <span class="token number">0</span> members <span class="token punctuation">(</span>00.00% of keys, avg size <span class="token number">0.00</span><span class="token punctuation">)</span>
<span class="token number">0</span> zsets with <span class="token number">0</span> members <span class="token punctuation">(</span>00.00% of keys, avg size <span class="token number">0.00</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>从这个命令的运行结果，我们可以看出：这个命令会扫描(Scan) Redis 中的所有 key ，会对 Redis 的性能有一点影响。并且，这种方式只能找出每种数据结构 top 1 bigkey（占用内存最大的 string 数据类型，包含元素最多的复合数据类型）。</p><p><strong>2、分析 RDB 文件</strong></p><p>通过分析 RDB 文件来找出 big key。这种方案的前提是你的 Redis 采用的是 RDB 持久化。</p><p>网上有现成的代码/工具可以直接拿来使用：</p>`,17),f={href:"https://github.com/sripathikrishnan/redis-rdb-tools",target:"_blank",rel:"noopener noreferrer"},y={href:"https://github.com/weiyanwei412/rdb_bigkeys",target:"_blank",rel:"noopener noreferrer"},R=i(`<h2 id="redis如何做内存优化" tabindex="-1"><a class="header-anchor" href="#redis如何做内存优化" aria-hidden="true">#</a> Redis如何做内存优化？</h2><h3 id="redis-server本身对内存的优化" tabindex="-1"><a class="header-anchor" href="#redis-server本身对内存的优化" aria-hidden="true">#</a> Redis Server本身对内存的优化</h3><p><strong>1. 共享对象池（Java中也存在类似优化）</strong></p><p>共享对象池是指Redis内部维护了[0-9999]的整数对象池，用于节约内存。除了整数值对象，其它类型如list、hash、set和zset内部元素也可以使用整数对象池。</p><p>但要注意当设置maxmemory，并启用LRU相关淘汰策略如，volatile-lru，allkeys-lru时，Redis禁止使用共享对象池。LRU算法需要获取对象最后被访问时间，以便淘汰最长未访问数据，每个对象最后访问时间存储在redisObject对象的lru字段。对象共享意味着多个引用共享同一个RedisObject，这时lru字段也会被共享，导致无法获取每个对象的最后访问时间。</p><p>当执行命令<code>set foo 1; set bar 1</code>时，foo 和 bar 指向的是同一个对象。所以如果value可以用整数表示的话，尽量用整数表示。不过比较坑的是当redis 设置最大内存上限和lru淘汰策略时就不能共享整数对象了。</p><p><strong>2. 字符串优化</strong></p><p>Redis没有采用原生C语言的字符串类型，而是自己实现了字符串结构，简单动态字符串（simple dynamic string，SDS）。其内部实现空间预分配机制，降低内存再分配次数。但要防止预分配带来的内存浪费，尽量减少字符串频繁修改操作append、setrange，改为直接使用set修改字符串，降低预分配带来的内存浪费和内存碎片。</p><h3 id="应用方面的优化" tabindex="-1"><a class="header-anchor" href="#应用方面的优化" aria-hidden="true">#</a> 应用方面的优化</h3><p><strong>1. 控制键的数量，使用hash代替多个key value。</strong></p><p>使用Redis不要进入一个误区，大量使用get/set这样的API，把其当成Memcached使用。对于存储相同的数据内容，利用Redis的数据结构降低外层键的数量，也可以节省大量内存。</p><p><strong>2. 缩减键值对象</strong></p><p>对key长度，设计键时，在完整描述业务情况下，键值越短越好。</p><p>value长度，值对象缩减比较复杂，常见的做法是把业务对象序列化成二进制数组放入Redis，这时就要选择更高效的序列化工具。值对象除了存储二进制数据之外，通常还会使用通用格式存储数据比如json、xml等作为字符串存储在Redis中，可使用通用压缩算法压缩json、xml后再存入Redis，从而降低内存占用。</p><h2 id="redis的事务-具体命令" tabindex="-1"><a class="header-anchor" href="#redis的事务-具体命令" aria-hidden="true">#</a> Redis的事务？具体命令？</h2><p><strong>Redis事务的概念：</strong></p><p>Redis 事务的本质是一组命令的集合。事务支持一次执行多个命令，一个事务中所有命令都会被序列化。在事务执行过程，会按照顺序串行化执行队列中的命令，其他客户端提交的命令请求不会插入到事务执行命令序列中</p><p>总结说：redis事务就是一次性、顺序性、排他性的执行一个队列中的一系列命令。</p><p><strong>Redis事务没有隔离级别的概念：</strong></p><p>批量操作在发送 EXEC 命令前被放入队列缓存，并不会被实际执行，也就不存在事务内的查询要看到事务里的更新，事务外查询不能看到。</p><div class="hint-container note"><p class="hint-container-title">为什么不支持回滚？</p><p>Redis 官网也解释了自己为啥不支持回滚。简单来说就是 Redis 开发者们觉得没必要支持回滚，这样更简单便捷并且性能更好。Redis 开发者觉得即使命令执行错误也应该在开发过程中就被发现而不是生产过程中。</p><p>可以将 Redis 中的事务就理解为 ：<strong>Redis 事务提供了一种将多个命令请求打包的功能。然后，再按顺序执行打包的所有命令，并且不会被中途打断。</strong></p></div><p><strong>Redis不保证原子性：</strong></p><p>Redis中，单条命令是原子性执行的，但事务不保证原子性，且没有回滚。事务中任意命令执行失败，其余的命令仍会被执行。</p><p><strong>Redis事务的三个阶段：</strong></p><ul><li>开始事务</li><li>命令入队</li><li>执行事务</li></ul><p><strong>Redis事务相关命令：</strong></p><p><strong>watch key1 key2</strong> ... : 监视一或多个key,如果在事务执行之前，被监视的key被其他命令改动，则事务被打断 （ 类似乐观锁 ）</p><p><strong>multi</strong> : 标记一个事务块的开始（ 之后的命令会被放入队列）</p><p><strong>exec</strong> : 执行所有事务块的命令 （ 一旦执行exec后，之前加的监控锁都会被取消掉 ）</p><p><strong>discard</strong> : 取消事务，放弃事务块中的所有命令</p><p><strong>unwatch</strong> : 取消watch对所有key的监控</p><blockquote><p>如下所示。如果在 set b bbb 处失败，set a 已成功不会回滚，set c 还会继续执行。</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>redis <span class="token number">127.0</span>.0.1:700<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span> multi
OK
redis <span class="token number">127.0</span>.0.1:700<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span> <span class="token builtin class-name">set</span> a aaa
QUEUED
redis <span class="token number">127.0</span>.0.1:700<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span> <span class="token builtin class-name">set</span> b bbb
QUEUED
redis <span class="token number">127.0</span>.0.1:700<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span> <span class="token builtin class-name">set</span> c ccc
QUEUED
redis <span class="token number">127.0</span>.0.1:700<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span> <span class="token builtin class-name">exec</span>
<span class="token number">1</span><span class="token punctuation">)</span> OK
<span class="token number">2</span><span class="token punctuation">)</span> OK
<span class="token number">3</span><span class="token punctuation">)</span> OK
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="redis都可以用在哪些场景-布隆过滤器" tabindex="-1"><a class="header-anchor" href="#redis都可以用在哪些场景-布隆过滤器" aria-hidden="true">#</a> Redis都可以用在哪些场景？（布隆过滤器）</h2><p><strong>热点数据的缓存</strong></p><p>由于redis访问速度块、支持的数据类型比较丰富，所以redis很适合用来存储热点数据，另外结合expire，我们可以设置过期时间然后再进行缓存更新操作，这个功能最为常见，我们几乎所有的项目都有所运用。</p><p><strong>限时业务的运用</strong></p><p>redis中可以使用expire命令设置一个键的生存时间，到时间后redis会删除它。利用这一特性可以运用在限时的优惠活动信息、手机验证码等业务场景。</p><p><strong>分布式锁</strong></p><p>这个主要利用redis的<code>setnx</code>命令进行，<code>setnx (set if not exists)</code> 就是如果不存在则成功设置缓存同时返回1，否则返回0。结合具体业务，我们可以给这个lock加一个过期时间，比如说30分钟执行一次的定时任务，那么这个过期时间设置为小于30分钟的一个时间 就可以，这个与定时任务的周期以及定时任务执行消耗时间相关。当然我们可以将这个特性运用于其他需要分布式锁的场景中，结合过期时间主要是防止死锁的出现。</p><p><strong>计数器相关问题</strong></p><p>redis由于<code>incrby</code>命令可以实现原子性的递增，所以可以运用于高并发的秒杀活动、分布式序列号的生成、具体业务还体现在比如限制一个手机号发多少条短信、一个接口一分钟限制多少请求、一个接口一天限制调用多少次等等。</p><p><strong>排行榜相关问题</strong></p><p>关系型数据库在排行榜方面查询速度普遍偏慢，所以可以借助redis的<code>SortedSet</code>进行热点数据的排序。在奶茶活动中，我们需要展示各个部门的点赞排行榜， 所以我针对每个部门做了一个SortedSet,然后以用户的openid作为上面的username，以用户的点赞数作为上面的score, 然后针对每个用户做一个hash,通过zrangebyscore就可以按照点赞数获取排行榜，然后再根据username获取用户的hash信息，这个当时在实际运用中性能体验也蛮不错的。</p><p><strong>延时操作</strong></p><p>比如在订单生产后我们占用了库存，10分钟后去检验用户是够真正购买，如果没有购买将该单据设置无效，同时还原库存。 在订单生产时，设置一个key，同时设置10分钟后过期， 我们在后台实现一个监听器，监听key的实效，监听到key失效时将后续逻辑加上。 当然我们也可以利用rabbitmq、activemq等消息中间件的延迟队列服务实现该需求。</p><p><strong>点赞、共同好友，队列等。。。</strong></p><h2 id="redis如何实现分布式锁" tabindex="-1"><a class="header-anchor" href="#redis如何实现分布式锁" aria-hidden="true">#</a> redis如何实现分布式锁？</h2><p>见上题。setnx。</p><h2 id="redis-可以做消息队列么" tabindex="-1"><a class="header-anchor" href="#redis-可以做消息队列么" aria-hidden="true">#</a> Redis 可以做消息队列么？</h2><p>Redis 5.0 新增加的一个数据结构 <code>Stream</code> 可以用来做消息队列，<code>Stream</code> 支持：</p><ul><li>发布 / 订阅模式</li><li>按照消费者组进行消费</li><li>消息持久化（ RDB 和 AOF）</li></ul><p>不过，和专业的消息队列相比，还是有很多欠缺的地方比如消息丢失和堆积问题不好解决。</p><p>我们通常建议是不需要使用 Redis 来做消息队列的，你完全可以选择市面上比较成熟的一些消息队列比如 RocketMQ、Kafka。</p>`,54),x={href:"https://javakeeper.starfish.ink/data-management/Redis/Redis-MQ.html",target:"_blank",rel:"noopener noreferrer"},_=i(`<h2 id="缓存击穿、缓存穿透、缓存雪崩含义-及预防措施。" tabindex="-1"><a class="header-anchor" href="#缓存击穿、缓存穿透、缓存雪崩含义-及预防措施。" aria-hidden="true">#</a> 缓存击穿、缓存穿透、缓存雪崩含义，及预防措施。</h2><h3 id="缓存穿透" tabindex="-1"><a class="header-anchor" href="#缓存穿透" aria-hidden="true">#</a> <strong>缓存穿透</strong></h3><p>缓存穿透是指缓存和数据库中都没有的数据，而用户不断发起请求，请求直接打在了数据库上。</p><p>最基本的就是首先做好参数校验，一些不合法的参数请求直接抛出异常信息返回给客户端。比如查询的数据库 id 不能小于 0、传入的邮箱格式不对的时候直接返回错误消息给客户端等等。</p><p><strong>1、缓存无效key</strong></p><p>如果缓存和数据库都查不到某个 key 的数据就写一个到 Redis 中去并设置过期时间，具体命令如下： <code>SET key value EX 10086</code> 。这种方式可以解决请求的 key 变化不频繁的情况，如果黑客恶意攻击，每次构建不同的请求 key，<strong>会导致 Redis 中缓存大量无效的 key</strong> 。很明显，这种方案并不能从根本上解决此问题。如果非要用这种方式来解决穿透问题的话，尽量将无效的 key 的过期时间设置短一点比如 1 分钟。</p><p>如果用 Java 代码展示的话，差不多是下面这样的：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token class-name">Object</span> <span class="token function">getObjectInclNullById</span><span class="token punctuation">(</span><span class="token class-name">Integer</span> id<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 从缓存中获取数据</span>
    <span class="token class-name">Object</span> cacheValue <span class="token operator">=</span> cache<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>id<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token comment">// 缓存为空</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>cacheValue <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 从数据库中获取</span>
        <span class="token class-name">Object</span> storageValue <span class="token operator">=</span> storage<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>key<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">// 缓存空对象</span>
        cache<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>key<span class="token punctuation">,</span> storageValue<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">// 如果存储数据为空，需要设置一个过期时间(300秒)</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>storageValue <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">// 必须设置过期时间，否则有被攻击的风险</span>
            cache<span class="token punctuation">.</span><span class="token function">expire</span><span class="token punctuation">(</span>key<span class="token punctuation">,</span> <span class="token number">60</span> <span class="token operator">*</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        <span class="token keyword">return</span> storageValue<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> cacheValue<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>2、布隆过滤器</strong></p><p>采用布隆过滤器，使用一个足够大的bitmap，用于存储可能访问的key，不存在的key直接被过滤；</p><p>布隆过滤器是一个非常神奇的数据结构，通过它我们可以非常方便地判断一个给定数据是否存在于海量数据中。我们需要的就是判断 key 是否合法。</p><p>具体是这样做的：把所有可能存在的请求的值都存放在布隆过滤器中，当用户请求过来，先判断用户发来的请求的值是否存在于布隆过滤器中。不存在的话，直接返回请求参数错误信息给客户端，存在的话才会走下面的流程。</p><p>加入布隆过滤器之后的缓存处理流程图如下。</p><figure><img src="https://javaguide.cn/assets/加入布隆过滤器后的缓存处理流程.79596186.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>需要注意的是布隆过滤器可能会存在误判的情况。总结来说就是： <strong>布隆过滤器说某个元素存在，小概率会误判。布隆过滤器说某个元素不在，那么这个元素一定不在。</strong></p><p><em>为什么会出现误判的情况呢? 我们还要从布隆过滤器的原理来说！</em></p><p>我们先来看一下，<strong>当一个元素加入布隆过滤器中的时候，会进行哪些操作：</strong></p><ol><li>使用布隆过滤器中的哈希函数对元素值进行计算，得到哈希值（有几个哈希函数得到几个哈希值）。</li><li>根据得到的哈希值，在位数组中把对应下标的值置为 1。</li></ol><p>我们再来看一下，<strong>当我们需要判断一个元素是否存在于布隆过滤器的时候，会进行哪些操作：</strong></p><ol><li>对给定元素再次进行相同的哈希计算；</li><li>得到值之后判断位数组中的每个元素是否都为 1，如果值都为 1，那么说明这个值在布隆过滤器中，如果存在一个值不为 1，说明该元素不在布隆过滤器中。</li></ol><p>然后，一定会出现这样一种情况：<strong>不同的字符串可能哈希出来的位置相同，这就会导致不存在的字符串会被认为存在。</strong> （可以适当增加位数组大小或者调整我们的哈希函数来降低概率）</p>`,21),O={href:"https://javaguide.cn/cs-basics/data-structure/bloom-filter/",target:"_blank",rel:"noopener noreferrer"},A=i('<h3 id="缓存雪崩" tabindex="-1"><a class="header-anchor" href="#缓存雪崩" aria-hidden="true">#</a> <strong>缓存雪崩</strong></h3><ul><li><p>大量的key设置了相同的过期时间，导致在缓存在同一时刻全部失效，造成瞬时DB请求量大、压力骤增，引起雪崩。</p><ul><li>方案1：给缓存设置过期时间时加上一个随机值时间，使得每个key的过期时间分布开来，不会集中在同一时刻失效。</li><li>方案2：缓存永不失效</li></ul></li><li><p>redis宕机。造成系统的所有访问，都要走数据库。</p><ul><li>方案1：分布式缓存，将大量的数据分开存放，如切片集群模式，如果数据量不大，可以采用副本集群模式，多个Redis存放一样的数据。</li><li>方案2：限流，避免同时处理大量的请求。</li></ul></li></ul><h3 id="缓存击穿" tabindex="-1"><a class="header-anchor" href="#缓存击穿" aria-hidden="true">#</a> 缓存击穿</h3><p>一个key非常热点，在不停的扛着大并发，大并发集中对这一个点进行访问，当这个key在失效的瞬间，持续的大并发就穿破缓存，直接请求数据库，就像在一个屏障上凿开了一个洞。</p><p>解决方案：设置热点数据永远不过期；或者加上互斥锁：在访问key之前，采用SETNX（set if not exists）来设置另一个短期key来锁住当前key的访问，访问结束再删除该短期key。</p><h2 id="布隆过滤器原理-应用场景" tabindex="-1"><a class="header-anchor" href="#布隆过滤器原理-应用场景" aria-hidden="true">#</a> 布隆过滤器原理，应用场景？</h2><p>见上方缓存穿透的解决方案2。</p><h2 id="如何解决缓存一致性问题" tabindex="-1"><a class="header-anchor" href="#如何解决缓存一致性问题" aria-hidden="true">#</a> 如何解决缓存一致性问题？</h2><p><strong>双删加超时</strong></p><p>在写库前后都进行<code>redis.del(key)</code>操作，并且设定合理的超时时间。这样最差的情况是在超时时间内存在不一致，当然这种情况极其少见，可能的原因就是服务宕机。此种情况可以满足绝大多数需求。 当然这种策略要考虑redis和数据库主从同步的耗时，所以在第二次删除前最好休眠一定时间，比如500毫秒，这样毫无疑问又增加了写请求的耗时。</p><p><strong>异步淘汰缓存</strong></p><p>订阅数据库变更日志，再操作缓存。拿 MySQL 举例，当一条数据发生修改时，MySQL 就会产生一条变更日志（Binlog），我们可以订阅这个日志，拿到具体操作的数据，然后再根据这条数据，去删除对应的缓存。</p><p>订阅变更日志，目前也有了比较成熟的开源中间件，例如阿里的 canal，使用这种方案的优点在于：</p><ul><li><strong>无需考虑写消息队列失败情况</strong>：只要写 MySQL 成功，Binlog 肯定会有</li><li><strong>自动投递到下游队列</strong>：canal 自动把数据库变更日志「投递」给下游的消息队列</li></ul><p>当然，与此同时，我们需要投入精力去维护 canal 的高可用和稳定性。</p><blockquote><p>如果你有留意观察很多数据库的特性，就会发现其实很多数据库都逐渐开始提供「订阅变更日志」的功能了，相信不远的将来，我们就不用通过中间件来拉取日志，自己写程序就可以订阅变更日志了，这样可以进一步简化流程。</p></blockquote><p>好处：业务代码侵入性低，将缓存与数据库不一致的时间尽可能缩小。</p>',17),w={href:"https://mp.weixin.qq.com/s?__biz=MzIyOTYxNDI5OA==&mid=2247487312&idx=1&sn=fa19566f5729d6598155b5c676eee62d&chksm=e8beb8e5dfc931f3e35655da9da0b61c79f2843101c130cf38996446975014f958a6481aacf1&scene=178&cur_album_id=1699766580538032128#rd",target:"_blank",rel:"noopener noreferrer"},B=e("h2",{id:"redis挂了怎么办",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#redis挂了怎么办","aria-hidden":"true"},"#"),s(" Redis挂了怎么办")],-1),F=e("p",null,"1、redis挂之前首先肯定要开持久化（rdb/aof/混合模式）",-1),S=e("p",null,"2、一般开混合，而如果开混合的话最多也就是损失几秒的数据",-1),E=e("p",null,"3、一般Redis挂的话基本不可能，一个大公司（不可能只有一个机房，肯定异地多活，很难全挂）",-1),D=e("p",null,"其他：哨兵监控进行主备切换，和防止节点挂掉引起的缓存雪崩问题",-1),q=e("h2",{id:"redis为什么那么快",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#redis为什么那么快","aria-hidden":"true"},"#"),s(" Redis为什么那么快？")],-1),I={href:"https://baijiahao.baidu.com/s?id=1708807538121555902&wfr=spider&for=pc",target:"_blank",rel:"noopener noreferrer"},z=e("h2",{id:"redis主从复制细节",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#redis主从复制细节","aria-hidden":"true"},"#"),s(" Redis主从复制细节？")],-1),j={href:"https://www.cnblogs.com/Eugene-Jin/p/10742424.html",target:"_blank",rel:"noopener noreferrer"},U=i('<h2 id="哪些场景下设置了缓存不如不设缓存" tabindex="-1"><a class="header-anchor" href="#哪些场景下设置了缓存不如不设缓存" aria-hidden="true">#</a> 哪些场景下设置了缓存不如不设缓存</h2><p>频繁写，少量读的场景。</p><h2 id="主从复制怎么自动扩容缩容" tabindex="-1"><a class="header-anchor" href="#主从复制怎么自动扩容缩容" aria-hidden="true">#</a> 主从复制怎么自动扩容缩容？</h2><h2 id="mapreduce原理" tabindex="-1"><a class="header-anchor" href="#mapreduce原理" aria-hidden="true">#</a> MapReduce原理</h2>',4);function C(M,V){const n=d("ExternalLinkIcon");return r(),o("div",null,[l,e("p",null,[e("a",c,[s("advanced-java - 缓存"),a(n)]),s("：advanced-java 这个项目中对缓存的介绍。干货。")]),e("p",null,[e("a",u,[s("Redis知识点 - JavaGuide"),a(n)])]),h,e("ol",null,[e("li",null,[e("a",g,[s("Redis 6.0 新特性-多线程连环 13 问"),a(n)])]),e("li",null,[e("a",b,[s("为什么 Redis 选择单线程模型"),a(n)])])]),k,e("p",null,[s("官方文档地址："),e("a",m,[s("https://redis.io/topics/persistence"),a(n)])]),v,e("ul",null,[e("li",null,[e("a",f,[s("redis-rdb-toolsopen"),a(n)]),s(" ：Python 语言写的用来分析 Redis 的 RDB 快照文件用的工具")]),e("li",null,[e("a",y,[s("rdb_bigkeysopen"),a(n)]),s(" : Go 语言写的用来分析 Redis 的 RDB 快照文件用的工具，性能更好。")])]),R,e("p",null,[s("相关文章推荐："),e("a",x,[s("Redis 消息队列的三种方案（List、Streams、Pub/Sub）"),a(n)])]),_,e("p",null,[s("参考："),e("a",O,[s("《不了解布隆过滤器？一文给你整的明明白白！》"),a(n)])]),A,e("p",null,[s("参考："),e("a",w,[s("缓存和数据库一致性问题，看这篇就够了"),a(n)])]),B,F,S,E,D,q,e("p",null,[s("参考："),e("a",I,[s("Redis 为什么这么快？这才是最完美的回答"),a(n)])]),z,e("p",null,[s("参考："),e("a",j,[s("Redis主从复制详解"),a(n)])]),U])}const L=t(p,[["render",C],["__file","index.html.vue"]]);export{L as default};
